SELECT AVG(participants) AS average_participants
FROM participation_data
WHERE program_id = 1 AND month_year LIKE '2015-10-%';

SELECT program_id, average_participants
FROM average_participation
WHERE year = 2015;

SELECT agency_id, SUM(budget) AS total_budget
FROM agencies
GROUP BY agency_id;

SELECT average_participants
FROM average_participation
WHERE program_id = 1;

SELECT agency_name 
FROM agencies 
WHERE budget = (SELECT MAX(budget) FROM agencies);

SELECT agency_name 
  FROM agencies 
  WHERE budget = (SELECT MAX(budget) FROM agencies);

SELECT COUNT(agency_id)
FROM agencies
WHERE num_employees > 1000;
